text:
I spent the day battling with jdk1.1.8, ant, and javavm and
finally got a working mysql-jdbc-mm port which builds 2.0.8
from source.

The battle would have been a bit easier, by the way, if the
'ant' port was built from source so I didn't have to fetch
and build it myself in order to debug some 'ant'-related
problems :-)

After applying the patch you'll need to delete
files/patch-Makefile as well as all the .orig files.

Here's the patch:

diff -ru mysql-jdbc-mm.old/Makefile mysql-jdbc-mm/Makefile
--- mysql-jdbc-mm.old/Makefile	Fri Jun  1 06:49:08 2001
+++ mysql-jdbc-mm/Makefile	Thu Nov 29 17:45:41 2001
@@ -6,28 +6,58 @@
 #

 PORTNAME=	mysql-jdbc-mm
-PORTVERSION=	1.2c
+PORTVERSION=	2.0.8
 CATEGORIES=	databases java
-MASTER_SITES=	http://mmmysql.sourceforge.net/dist/
-DISTNAME=	mm.mysql.jdbc-${PORTVERSION}
+MASTER_SITES=	${MASTER_SITE_SOURCEFORGE}
+MASTER_SITE_SUBDIR=	mmmysql
+DISTNAME=	mm.mysql-${PORTVERSION}
+EXTRACT_SUFX=	-you-must-unjar-me.jar

 MAINTAINER=	dglo@SSEC.WISC.EDU

-BUILD_DEPENDS=	${LOCALBASE}/jdk1.1.8/bin/javac:${PORTSDIR}/java/jdk
+BUILD_DEPENDS=	${JAVA_HOME}/bin/javac:${PORTSDIR}/java/jdk13-beta \
+		ant:${PORTSDIR}/devel/jakarta-ant
+RUN_DEPENDS=	${JAVA_HOME}/bin/java:${PORTSDIR}/java/jdk13-beta

-ALL_TARGET=	jar
+JAVA_HOME?=	${PREFIX}/jdk1.3.1
+
+EXTRACT_CMD=	${JAVA_HOME}/bin/jar
+EXTRACT_BEFORE_ARGS=	-xf
+
+post-patch:
+	(cd ${WRKSRC}; mv build.xml build.xml.unpatched; \
+	 sed -e "s;%%WRKSRC%%;${WRKSRC};g" -e "s;%%PREFIX%%;${PREFIX};g" \
+		< build.xml.unpatched > build.xml)
+	(cd ${WRKSRC}; mv j1c j1c.unpatched; \
+	 sed "s;%%PREFIX%%;${PREFIX};g" < j1c.unpatched > j1c; \
+	 chmod +x j1c)
+
+do-build:
+	(cd ${WRKSRC}; env JAVA_HOME=${JAVA_HOME} ant clean dist)
+.if !defined(NOPORTDOCS)
+	(cd ${WRKSRC}; ${MKDIR} doc; \
+	 ${JAVA_HOME}/bin/javadoc -d doc -package \
+	     org.gjt.mm.mysql org.gjt.mm.mysql.jdbc2)
+.endif

 do-install:
 	@${MKDIR} ${PREFIX}/share/java/classes
-	@${INSTALL_DATA} ${WRKSRC}/mysql_comp.jar ${LOCALBASE}/share/java/classes
-
-post-install:
+	@${INSTALL_DATA} ${WRKDIR}/mm.mysql-${PORTVERSION}.jar \
+		${PREFIX}/share/java/classes
 .if !defined(NOPORTDOCS)
 	@${MKDIR} ${PREFIX}/share/doc/mysql-jdbc
 	@(cd ${WRKSRC}/doc && ${TAR} -c -f - .) \
 		| (cd ${PREFIX}/share/doc/mysql-jdbc && ${TAR} --unlink -x -f -)
+.endif
+
+post-install:
+	${ECHO} share/java/classes/mm.mysql-${PORTVERSION}.jar >> ${TMPPLIST}
+.if !defined(NOPORTDOCS)
 	@(cd ${PREFIX} \
 		&& find share/doc/mysql-jdbc -type f -print >> ${TMPPLIST})
+	${ECHO} "@dirrm share/java/mysql-jdbc" >> ${TMPPLIST}
 .endif
+	${ECHO} "@unexec ${RMDIR} %D/share/java/classes 2>/dev/null || true" >> ${TMPPLIST}
+	${ECHO} "@unexec ${RMDIR} %D/share/java 2>/dev/null || true" >> ${TMPPLIST}

 .include <bsd.port.mk>
