+-		// connection in the context of a transaction and
+-		// register it with the resource manager so it can
+-		// be shared.
+-		try {
+-		    _txConn = new TxConnection();
+-		    if ( _underlying != null ) {
+-			_txConn.conn = _underlying;
+-			_underlying = null;
+-		    } else
+-			_txConn.conn = _resManager.newConnection();
